TaskController = class()

function TaskController:ctor(player)
    self.userId = player.userId
    self.winProgresses = {}
end

function TaskController:packingProgressData(player, taskTypeId, gameType, remarks, value)
    local data = {
        Type = taskTypeId,
        GameType = gameType,
        Remarks = remarks,
        Value = value or 1
    }
    if taskTypeId == Define.TaskType.Fright.WinKill then
        table.insert(self.winProgresses, data)
    else
        self:saveTaskProcesses(player, data)
    end

end

function TaskController:saveTaskProcesses(player, progress)
    for _, task_progress in pairs(player.task_progresses) do
        if task_progress.Type == progress.Type
                and task_progress.Remarks == progress.Remarks
                and task_progress.GameType == progress.GameType
        then
            task_progress.Value = task_progress.Value + progress.Value
            return
        end
    end
    table.insert(player.task_progresses, progress)
end

return TaskController